"use strict";(globalThis.webpackChunkship_it_book=globalThis.webpackChunkship_it_book||[]).push([[898],{8142(e,t,n){n.r(t),n.d(t,{assets:()=>h,contentTitle:()=>a,default:()=>c,frontMatter:()=>r,metadata:()=>o,toc:()=>d});const o=JSON.parse('{"id":"part-3-design-the-solution/chapter-3-2-designing-before-you-code","title":"Chapter 3.2 \u2014 Designing Before You Code","description":"Maps, flows, and wireframes that save months.","source":"@site/docs/part-3-design-the-solution/chapter-3-2-designing-before-you-code.mdx","sourceDirName":"part-3-design-the-solution","slug":"/part-3-design-the-solution/chapter-3-2-designing-before-you-code","permalink":"/ship-it-book/part-3-design-the-solution/chapter-3-2-designing-before-you-code","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"Chapter 3.2 \u2014 Designing Before You Code","description":"Maps, flows, and wireframes that save months.","sidebar_label":"3.2 \u2014 Designing Before You Code"},"sidebar":"book","previous":{"title":"3.1 \u2014 System Thinking","permalink":"/ship-it-book/part-3-design-the-solution/chapter-3-1-system-thinking"},"next":{"title":"Part 4 \u2014 Build It","permalink":"/ship-it-book/part-4-build-it/"}}');var i=n(4848),s=n(8453);const r={title:"Chapter 3.2 \u2014 Designing Before You Code",description:"Maps, flows, and wireframes that save months.",sidebar_label:"3.2 \u2014 Designing Before You Code"},a="Designing Before You Code",h={},d=[{value:"The Cost of Coding Too Early",id:"the-cost-of-coding-too-early",level:2},{value:"The Cost Data",id:"the-cost-data",level:3},{value:"The Design Hierarchy",id:"the-design-hierarchy",level:2},{value:"How to Create User Journey Maps",id:"how-to-create-user-journey-maps",level:2},{value:"The Technical Design Document",id:"the-technical-design-document",level:2},{value:"Technical Design Document Template",id:"technical-design-document-template",level:3},{value:"The One-Week Rule",id:"the-one-week-rule",level:2},{value:"Case Study: A Product That Saved Months by Designing First",id:"case-study-a-product-that-saved-months-by-designing-first",level:2},{value:"Tools and Workflows for Design-First Development",id:"tools-and-workflows-for-design-first-development",level:2},{value:"The Hard Truth",id:"the-hard-truth",level:2},{value:"Your Turn",id:"your-turn",level:2},{value:"What You Learned",id:"what-you-learned",level:2}];function l(e){const t={code:"code",h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",p:"p",pre:"pre",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",ul:"ul",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"designing-before-you-code",children:"Designing Before You Code"})}),"\n",(0,i.jsx)(t.p,{children:"You've identified the problem. You understand the system. Now you want to open your editor and start coding. Don't."}),"\n",(0,i.jsx)(t.p,{children:"The gap between understanding a problem and building a solution is where most products die. You think you know what to build. You don't. Not until you've designed it on paper first."}),"\n",(0,i.jsx)(t.h2,{id:"the-cost-of-coding-too-early",children:"The Cost of Coding Too Early"}),"\n",(0,i.jsx)(t.p,{children:"Code is expensive to change. A wireframe takes five minutes to redraw. A database migration takes hours. A whole feature that you built and need to remove takes days."}),"\n",(0,i.jsx)(t.p,{children:"When you code too early, every mistake costs time. When you design first, mistakes cost nothing. You catch assumptions before they become bugs. You find missing pieces before they become blockers."}),"\n",(0,i.jsx)(t.p,{children:"I've never regretted spending too much time on design. I've never regretted building too late. I've spent months rewriting code I could have designed right the first time."}),"\n",(0,i.jsx)(t.h3,{id:"the-cost-data",children:"The Cost Data"}),"\n",(0,i.jsx)(t.p,{children:"Let's talk numbers. Industry data shows that fixing a bug found in production costs 100x more than fixing the same bug found in the design phase. A requirements error caught during design costs about $100 to fix. The same error caught in production costs $10,000 or more."}),"\n",(0,i.jsx)(t.p,{children:"This isn't because production bugs are fundamentally harder. It's because of everything wrapped around that bug. The code review. The deployment pipeline. The migration scripts. The communication with affected users. The rollback plan. The postmortem. The reputation damage."}),"\n",(0,i.jsx)(t.p,{children:"A design problem caught at the wireframe stage is a five-minute fix. Redraw the box. Rearrange the flow. You're done. The same problem discovered after you've built the database schema, wired up the API, written the frontend components, and deployed to staging requires untangling all of that. Hours or days."}),"\n",(0,i.jsx)(t.p,{children:"This is the fundamental economics of design-first development."}),"\n",(0,i.jsx)(t.h2,{id:"the-design-hierarchy",children:"The Design Hierarchy"}),"\n",(0,i.jsx)(t.p,{children:"Start with user flows. Before you design a single screen, map the journey. What does the user do first? What do they see next? What are the decision points? Where could they get stuck?"}),"\n",(0,i.jsx)(t.p,{children:"A user flow is a series of boxes and arrows. Each box is a step. Each arrow is a decision. Don't worry about aesthetics. Just capture the sequence."}),"\n",(0,i.jsx)(t.p,{children:"Next, wireframes. For each step in your flow, draw the interface. Use a tool like Excalidraw, Figma, or a whiteboard. Black and white. No colors. No fonts. Just layout and content."}),"\n",(0,i.jsx)(t.p,{children:"Wireframes test your assumptions about what information users need and what actions they take. If a wireframe feels confusing, the real interface will be impossible."}),"\n",(0,i.jsx)(t.p,{children:"Finally, prototypes. Link your wireframes together into a clickable flow. Use a simple tool or just print them out and walk through them. Test the flow yourself. Then test it with someone else."}),"\n",(0,i.jsx)(t.h2,{id:"how-to-create-user-journey-maps",children:"How to Create User Journey Maps"}),"\n",(0,i.jsx)(t.p,{children:"A user journey map goes deeper than a flow. It captures the emotional state of the user at each step. It reveals friction points that wireframes won't show."}),"\n",(0,i.jsx)(t.p,{children:"Draw a grid. The rows are: Stage, Actions, Thoughts, Emotions, Pain Points, Opportunities. The columns are the stages of your user's journey."}),"\n",(0,i.jsx)(t.p,{children:"For a subscription SaaS, the stages might be: Discovery \u2192 Signup \u2192 First Use \u2192 Regular Use \u2192 Renewal."}),"\n",(0,i.jsx)(t.p,{children:"Fill in each cell. For the Discovery stage:"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Actions"}),': Googles for "project management tool," reads reviews, visits your pricing page']}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Thoughts"}),": \"This looks promising but I'm not sure if it's worth the price\""]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Emotions"}),": Curious but skeptical"]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Pain Points"}),": Hard to compare features with competitors, no clear pricing"]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)(t.strong,{children:"Opportunities"}),": Add a comparison page with competitors, offer a free trial with no credit card"]}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"The emotional arc is the most revealing part. If your journey map shows a steep drop in emotion anywhere, you've found a systemic problem. A journey map for a fintech app might reveal that users feel anxious during account setup (emotional drop) and relieved when they see their first balance (emotional rise). If your journey has no emotional drop, you're not looking hard enough."}),"\n",(0,i.jsx)(t.p,{children:"Once you have the journey map, zoom in on the pain points. These are your design priorities. Every feature you build should address a specific pain point from the map. If a feature doesn't connect to a pain point, it's optional at best and distracting at worst."}),"\n",(0,i.jsx)(t.h2,{id:"the-technical-design-document",children:"The Technical Design Document"}),"\n",(0,i.jsx)(t.p,{children:"Before you write a single line of code, write a technical design document. Include:"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"Data model: what entities exist and how they relate"}),"\n",(0,i.jsx)(t.li,{children:"API surface: what endpoints you need"}),"\n",(0,i.jsx)(t.li,{children:"Key algorithms: complex logic explained in plain language"}),"\n",(0,i.jsx)(t.li,{children:"Dependencies: what external services you'll use"}),"\n",(0,i.jsx)(t.li,{children:"Risks: what could go wrong and how you'll handle it"}),"\n"]}),"\n",(0,i.jsx)(t.p,{children:"This document is not for your manager. It's for you. It forces you to think through every aspect before you commit to code. If you can't describe how something works in plain language, you don't understand it well enough to code it."}),"\n",(0,i.jsx)(t.h3,{id:"technical-design-document-template",children:"Technical Design Document Template"}),"\n",(0,i.jsx)(t.p,{children:"Here's the template I use. Copy it."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Title"}),": [Feature Name] Technical Design"]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"1. Goal"}),"\nOne paragraph. What are we building and why?"]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"2. Data Model"})}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{children:"entities/\n  User\n    - id: UUID (primary key)\n    - email: string (unique, indexed)\n    - created_at: timestamp\n  Project\n    - id: UUID (primary key)\n    - name: string\n    - owner_id: UUID (FK to User)\n    - created_at: timestamp\n"})}),"\n",(0,i.jsx)(t.p,{children:"List every entity, every field, and the relationships. This will become your database schema."}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"3. API Surface"})}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{children:"POST   /api/projects          \u2014 Create a project\nGET    /api/projects          \u2014 List user's projects\nGET    /api/projects/:id      \u2014 Get project details\nPUT    /api/projects/:id      \u2014 Update project\nDELETE /api/projects/:id      \u2014 Delete project\n"})}),"\n",(0,i.jsx)(t.p,{children:"Define each endpoint. Include request/response shapes if they're complex."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"4. Key Logic"}),'\nPlain language description of complex operations. No code. For example: "When a user creates a project, we need to verify they haven\'t reached their plan limit, create the project record, set up default permissions for the owner, and trigger a webhook to their connected Slack workspace."']}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"5. Dependencies"}),"\nList every external service this feature touches. Auth. Payments. Email. File storage. Each dependency is a risk."]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.strong,{children:"6. Risks and Mitigations"})}),"\n",(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.th,{children:"Risk"}),(0,i.jsx)(t.th,{children:"Likelihood"}),(0,i.jsx)(t.th,{children:"Impact"}),(0,i.jsx)(t.th,{children:"Mitigation"})]})}),(0,i.jsxs)(t.tbody,{children:[(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Duplicate project names"}),(0,i.jsx)(t.td,{children:"Low"}),(0,i.jsx)(t.td,{children:"Low"}),(0,i.jsx)(t.td,{children:"Add unique constraint on name per owner"})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:"Rate limiting from email service"}),(0,i.jsx)(t.td,{children:"Medium"}),(0,i.jsx)(t.td,{children:"Medium"}),(0,i.jsx)(t.td,{children:"Queue emails, handle retries with exponential backoff"})]})]})]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"7. Open Questions"}),"\nList anything you're not sure about. This section is the most valuable. It surfaces assumptions before they become bugs."]}),"\n",(0,i.jsx)(t.p,{children:"When you finish the document, share it with another developer. Ask them: \"What did I miss?\" They will find things you didn't see. That's the whole point."}),"\n",(0,i.jsx)(t.h2,{id:"the-one-week-rule",children:"The One-Week Rule"}),"\n",(0,i.jsx)(t.p,{children:"Spend at least one week on design for every month of expected development. If you think your MVP will take three months, spend three weeks designing it."}),"\n",(0,i.jsx)(t.p,{children:"This sounds like a lot. It's not. The design phase uncovers problems that would take months to fix in code. The one-week rule gives you the clarity to build fast once you start coding."}),"\n",(0,i.jsx)(t.p,{children:"Here's what happens when you skip the one-week rule. A team I worked with built a billing system for their SaaS product. They spent two days on design and six weeks on implementation. In week three of implementation, they discovered they needed to support prorated refunds. The data model didn't support it. They had to redesign the database, rewrite three API endpoints, and update all the frontend billing pages. The redesign alone took two more weeks."}),"\n",(0,i.jsx)(t.p,{children:'Had they spent one week on design upfront, they would have listed "prorated refunds" as a key logic question in the design document. They\'d have realized on day three, not week three. The one-week rule would have saved them two weeks of rework.'}),"\n",(0,i.jsx)(t.h2,{id:"case-study-a-product-that-saved-months-by-designing-first",children:"Case Study: A Product That Saved Months by Designing First"}),"\n",(0,i.jsx)(t.p,{children:"A well-known story in product circles is the redesign of the Mint.com onboarding flow. The original flow took users through a 12-step setup process. Analytics showed an 80% drop-off between step 1 and step 12."}),"\n",(0,i.jsx)(t.p,{children:"The team wanted to rebuild the entire flow. Engineering estimated three months. Instead, the product manager spent three weeks on design. She mapped the user journey. She interviewed users at each step. She discovered the real problem: users were overwhelmed by the number of choices in step 2 (categorization of expenses)."}),"\n",(0,i.jsx)(t.p,{children:'She redesigned the flow around a single insight: start with the benefit, not the setup. The new flow: "Link your bank account. Here\'s your spending summary. You can edit categories later." The 12 steps became 3.'}),"\n",(0,i.jsx)(t.p,{children:"Three weeks of design. Two weeks of implementation. The new flow increased completion rates from 20% to 70%."}),"\n",(0,i.jsx)(t.p,{children:"The team saved two months of development by spending three weeks on design. They didn't build a complex solution to the wrong problem. They understood the user's emotional state and designed around it."}),"\n",(0,i.jsx)(t.h2,{id:"tools-and-workflows-for-design-first-development",children:"Tools and Workflows for Design-First Development"}),"\n",(0,i.jsx)(t.p,{children:"You don't need expensive tools to design first. Here's what I recommend at each stage."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"User flows"}),": Paper, whiteboard, or Excalidraw. The simpler the tool, the faster you iterate. Digital tools can make you obsessed with aesthetics before you've validated the logic."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Wireframes"}),': Balsamiq, Excalidraw, or Figma with wireframe kits. Keep it black and white. No branding. No colors. Colors create emotional reactions that distract from structural feedback. A user will say "I don\'t like the blue" when what they mean is "I don\'t understand where this button goes."']}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Prototypes"}),": Figma with prototyping mode, or a simple HTML page. The goal is interactivity, not fidelity. You can even print wireframes and walk through them with a user. Low-fidelity prototypes get better feedback because users feel more comfortable criticizing them."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Technical design"}),": A document in Notion, Google Docs, or Markdown. The format matters less than the act of writing. Writing forces precision. You can't hand-wave in a document the way you can in a conversation."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"The workflow"}),": Start with the user journey map (one session). Draw the user flows from the journey (one session). Wireframe each flow step (several sessions). Build a clickable prototype (one session). Test with someone else (one session). Write the technical design document (one session). Only then, open your editor."]}),"\n",(0,i.jsx)(t.p,{children:"Each session is 30-60 minutes. The entire process takes a week for most features. That week saves you from building the wrong thing."}),"\n",(0,i.jsx)(t.h2,{id:"the-hard-truth",children:"The Hard Truth"}),"\n",(0,i.jsx)(t.p,{children:"Designing first requires patience. It feels like you're not making progress. You have nothing to show for your work. No GitHub commits. No running code. Just sketches and documents."}),"\n",(0,i.jsx)(t.p,{children:"But these sketches and documents are the most valuable output you'll create. They're your blueprint. A builder without a blueprint wastes materials. A developer without a design wastes time."}),"\n",(0,i.jsx)(t.p,{children:"You can build a house without blueprints. It just won't be the house you want. Same with software. You can start coding without a design. You just won't ship the product you imagined."}),"\n",(0,i.jsx)(t.p,{children:"The resistance to designing first is psychological, not practical. You feel productive when you're typing. You feel anxious when you're drawing boxes on a whiteboard. That anxiety is the feeling of learning. Sit with it. Design anyway."}),"\n",(0,i.jsx)(t.h2,{id:"your-turn",children:"Your Turn"}),"\n",(0,i.jsx)(t.p,{children:"Take one feature you plan to build. Do not open your editor. Spend 30 minutes drawing the user flow on paper. Then spend 30 minutes sketching wireframes for each step. Then write the technical design document using the template in this chapter. Finally, create a user journey map with the emotional arc."}),"\n",(0,i.jsx)(t.p,{children:"If you find yourself reaching for your keyboard, stop. You're not ready."}),"\n",(0,i.jsx)(t.h2,{id:"what-you-learned",children:"What You Learned"}),"\n",(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsx)(t.li,{children:"Code is expensive to change; paper is free"}),"\n",(0,i.jsx)(t.li,{children:"Fixing a bug in production costs 100x more than in design"}),"\n",(0,i.jsx)(t.li,{children:"Design in layers: user journey map \u2192 flows \u2192 wireframes \u2192 prototypes \u2192 technical design"}),"\n",(0,i.jsx)(t.li,{children:"A technical design document forces you to think before you commit"}),"\n",(0,i.jsx)(t.li,{children:"The one-week rule: one week of design per month of development"}),"\n",(0,i.jsx)(t.li,{children:"User journey maps reveal emotional friction points"}),"\n",(0,i.jsx)(t.li,{children:"Designing first feels unproductive but saves the most time"}),"\n"]})]})}function c(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(l,{...e})}):l(e)}},8453(e,t,n){n.d(t,{R:()=>r,x:()=>a});var o=n(6540);const i={},s=o.createContext(i);function r(e){const t=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:r(e.components),o.createElement(s.Provider,{value:t},e.children)}}}]);